'use client'

import React, { useState } from 'react'
import { cn } from '@/lib/utils'
import { useDeckBuilder } from '@/contexts/DeckBuilderContext'
import { DeckSurface } from './DeckSurface'
import { CardBrowseInterface } from '@/components/cards/CardBrowseInterface'
import { MobileDeckBuilder } from './MobileDeckBuilder'
import { DeckHeader } from './DeckHeader'
import { CreateDeckModal } from './CreateDeckModal'
import { Button } from '@/components/atoms/Button/Button'
import { ChevronLeft, ChevronRight, Save, Undo, Redo, Download, Upload, Plus, FileText, Import } from 'lucide-react'
import { DndProvider } from 'react-dnd'
import { HTML5Backend } from 'react-dnd-html5-backend'

interface DeckBuilderLayoutProps {
  className?: string
}

export function DeckBuilderLayout({ className }: DeckBuilderLayoutProps) {
  const {
    deck,
    isDirty,
    isSaving,
    saveDeck,
    canUndo,
    canRedo,
    undo,
    redo,
    addCard,
    createDeck,
  } = useDeckBuilder()
  
  const [isPanelCollapsed, setIsPanelCollapsed] = useState(false)
  const [activeView, setActiveView] = useState<'desktop' | 'mobile-deck' | 'mobile-browse'>('desktop')
  const [showCreateModal, setShowCreateModal] = useState(false)
  
  // Detect mobile viewport
  const isMobile = typeof window !== 'undefined' && window.innerWidth < 1024
  
  // Use mobile layout on mobile devices
  if (isMobile) {
    return <MobileDeckBuilder className={className} />
  }
  
  // Show welcome screen when no deck is loaded
  if (!deck) {
    return (
      <>
        <div className={cn('flex flex-col items-center justify-center min-h-[600px] text-center px-4', className)}>
          <div className="max-w-md space-y-6">
            {/* Welcome Icon */}
            <div
              className="w-24 h-24 mx-auto rounded-full flex items-center justify-center"
              style={{ background: "rgba(139, 92, 246, 0.1)" }}
            >
              <FileText className="w-10 h-10" style={{ color: "var(--brand-primary, #8B5CF6)" }} />
            </div>

            {/* Welcome Text */}
            <div>
              <h1
                className="font-barlow-condensed font-bold mb-2"
                style={{ fontSize: 28, color: "var(--text-primary, #F0EEFF)" }}
              >
                Welcome to Deck Builder
              </h1>
              <p style={{ fontSize: 15, color: "var(--text-secondary, #B8B0D8)" }}>
                Create competitive decks for Magic: The Gathering, Pokémon, Yu-Gi-Oh!, and One Piece TCG.
              </p>
            </div>

            {/* Quick Actions */}
            <div className="space-y-3 w-full">
              <Button
                onClick={() => setShowCreateModal(true)}
                className="w-full rounded-[10px]"
                size="large"
                style={{ background: "var(--brand-primary, #8B5CF6)", color: "#fff" }}
              >
                <Plus className="w-4 h-4 mr-2" />
                Create New Deck
              </Button>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                <Button
                  variant="tonal"
                  className="w-full rounded-[10px]"
                  style={{ border: "1px solid var(--border-default, #2C2A4A)" }}
                  onClick={() => {
                    console.log('Load existing deck')
                  }}
                >
                  <FileText className="w-4 h-4 mr-2" />
                  Load Deck
                </Button>

                <Button
                  variant="tonal"
                  className="w-full rounded-[10px]"
                  style={{ border: "1px solid var(--border-default, #2C2A4A)" }}
                  onClick={() => {
                    console.log('Import deck')
                  }}
                >
                  <Import className="w-4 h-4 mr-2" />
                  Import Deck
                </Button>
              </div>
            </div>

            {/* Feature Highlights */}
            <div className="text-left space-y-3 text-sm" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
              <div className="flex items-start gap-2">
                <div className="w-1.5 h-1.5 rounded-full mt-2 flex-shrink-0" style={{ background: "var(--brand-primary, #8B5CF6)" }} />
                <span>Format-specific validation for all supported games</span>
              </div>
              <div className="flex items-start gap-2">
                <div className="w-1.5 h-1.5 rounded-full mt-2 flex-shrink-0" style={{ background: "var(--brand-primary, #8B5CF6)" }} />
                <span>Real-time pricing and collection integration</span>
              </div>
              <div className="flex items-start gap-2">
                <div className="w-1.5 h-1.5 rounded-full mt-2 flex-shrink-0" style={{ background: "var(--brand-primary, #8B5CF6)" }} />
                <span>Share decks with the community</span>
              </div>
            </div>
          </div>
        </div>
        
        {/* Create Deck Modal */}
        <CreateDeckModal
          isOpen={showCreateModal}
          onClose={() => setShowCreateModal(false)}
          onCreated={(newDeck) => {
            // Handle deck creation via context
            createDeck(newDeck.name, newDeck.game, newDeck.format)
            setShowCreateModal(false)
          }}
        />
      </>
    )
  }
  
  return (
    <DndProvider backend={HTML5Backend}>
      <div className={cn('flex flex-col h-full', className)}>
      {/* Header with deck info and actions */}
      <div
        className="backdrop-blur"
        style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)", background: "rgba(24, 22, 42, 0.95)" }}
      >
        <div className="flex items-center justify-between h-14 px-4">
          <DeckHeader deck={deck} />
          
          <div className="flex items-center gap-2">
            {/* Undo/Redo */}
            <div className="flex items-center gap-1 mr-2">
              <Button
                variant="text"
                size="small"
                onClick={undo}
                disabled={!canUndo}
                className="h-8 w-8 p-0"
                title="Undo (Ctrl+Z)"
              >
                <Undo className="h-4 w-4" />
              </Button>
              <Button
                variant="text"
                size="small"
                onClick={redo}
                disabled={!canRedo}
                className="h-8 w-8 p-0"
                title="Redo (Ctrl+Y)"
              >
                <Redo className="h-4 w-4" />
              </Button>
            </div>
            
            {/* Import/Export */}
            <Button
              variant="text"
              size="small"
              className="h-8 gap-1"
              title="Import deck"
            >
              <Upload className="h-4 w-4" />
              <span className="hidden sm:inline">Import</span>
            </Button>
            <Button
              variant="text"
              size="small"
              className="h-8 gap-1"
              title="Export deck"
            >
              <Download className="h-4 w-4" />
              <span className="hidden sm:inline">Export</span>
            </Button>
            
            {/* Save */}
            <Button
              variant={isDirty ? 'filled' : 'text'}
              size="small"
              onClick={saveDeck}
              disabled={isSaving || !isDirty}
              className="h-8 gap-1"
            >
              <Save className="h-4 w-4" />
              <span className="hidden sm:inline">
                {isSaving ? 'Saving...' : isDirty ? 'Save' : 'Saved'}
              </span>
            </Button>
          </div>
        </div>
      </div>
      
      {/* Main content area */}
      <div className="flex-1 flex overflow-hidden">
        {/* Mobile view toggle */}
        {isMobile && (
          <div className="flex justify-center gap-2 p-2 border-b md:hidden">
            <Button
              variant={activeView === 'mobile-browse' ? 'filled' : 'tonal'}
              size="small"
              onClick={() => setActiveView('mobile-browse')}
            >
              Browse Cards
            </Button>
            <Button
              variant={activeView === 'mobile-deck' ? 'filled' : 'tonal'}
              size="small"
              onClick={() => setActiveView('mobile-deck')}
            >
              Deck
            </Button>
          </div>
        )}
        
        {/* Desktop split view */}
        <div className="flex-1 flex">
          {/* Left panel - Card Browser */}
          <div
            className={cn(
              'transition-all duration-300 hidden lg:block',
              {
                'w-0 overflow-hidden': isPanelCollapsed,
                'w-full lg:w-1/2': !isPanelCollapsed,
              }
            )}
            style={{ background: "var(--bg-surface-1, #18162A)", borderRight: "1px solid var(--border-default, #2C2A4A)" }}
          >
            <CardBrowseInterface
              isDeckBuilder={true}
              lockedGame={deck.game}
              lockedGameDisplayName={deck.game}
              lockedFormat={deck.format}
              title="Add Cards to Deck"
              description={`Browse ${deck.game} cards${deck.format ? ` for ${deck.format}` : ''}`}
              showGameBadges={false}
              hideGameFilter={true}
              onCardAdd={(card, zone) => {
                addCard(card, zone || 'main')
              }}
              enableDragDrop={true}
              className="h-full"
            />
          </div>
          
          {/* Collapse toggle button */}
          <button
            onClick={() => setIsPanelCollapsed(!isPanelCollapsed)}
            className="hidden md:flex items-center justify-center w-6 h-12 my-auto rounded-r-md transition-colors"
            style={{ background: "var(--bg-surface-2, #21203A)", color: "var(--text-tertiary, #7B72A8)" }}
            aria-label={isPanelCollapsed ? 'Expand card browser panel' : 'Collapse card browser panel'}
          >
            {isPanelCollapsed ? (
              <ChevronRight className="h-4 w-4" />
            ) : (
              <ChevronLeft className="h-4 w-4" />
            )}
          </button>
          
          {/* Right panel - Deck Surface */}
          <div
            className={cn(
              'flex-1 overflow-hidden',
              {
                'hidden md:block': isMobile && activeView === 'mobile-browse',
                'block': !isMobile || activeView === 'mobile-deck',
              }
            )}
            style={{ background: "var(--bg-base, #09090F)" }}
          >
            <div className="h-full overflow-y-auto p-4">
              <DeckSurface deck={deck} />
            </div>
          </div>
        </div>
      </div>
      
      {/* Keyboard shortcuts handler */}
      <KeyboardShortcuts />
      </div>
    </DndProvider>
  )
}

function KeyboardShortcuts() {
  const { undo, redo, saveDeck, canUndo, canRedo, isDirty } = useDeckBuilder()
  
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ctrl/Cmd + Z for undo
      if ((e.ctrlKey || e.metaKey) && e.key === 'z' && !e.shiftKey) {
        e.preventDefault()
        if (canUndo) undo()
      }
      
      // Ctrl/Cmd + Y or Ctrl/Cmd + Shift + Z for redo
      if ((e.ctrlKey || e.metaKey) && (e.key === 'y' || (e.key === 'z' && e.shiftKey))) {
        e.preventDefault()
        if (canRedo) redo()
      }
      
      // Ctrl/Cmd + S for save
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        if (isDirty) saveDeck()
      }
    }
    
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [undo, redo, saveDeck, canUndo, canRedo, isDirty])
  
  return null
}

'use client'

import React, { useState } from 'react'
import { Deck } from '@/types/deck'
import { useDeckBuilder } from '@/contexts/DeckBuilderContext'
import { Input } from '@/components/atoms/Input/Input'
import { Button } from '@/components/atoms/Button/Button'
import { Edit2, Check, X, Globe, Lock } from 'lucide-react'
import { ValidationStatusBadge } from './DeckValidationPanel'

interface DeckHeaderProps {
  deck: Deck
}

export function DeckHeader({ deck }: DeckHeaderProps) {
  const { updateDeckName, togglePublicVisibility, stats, validation, realtimeValidation } = useDeckBuilder()
  const [isEditing, setIsEditing] = useState(false)
  const [editedName, setEditedName] = useState(deck.name)
  
  const handleSaveName = () => {
    updateDeckName(editedName)
    setIsEditing(false)
  }
  
  const handleCancelEdit = () => {
    setEditedName(deck.name)
    setIsEditing(false)
  }
  
  const getGameStyle = (game: string) => {
    switch (game) {
      case 'MTG': return { color: 'var(--game-mtg, #A78BFA)', bg: 'rgba(167, 139, 250, 0.12)', border: 'rgba(167, 139, 250, 0.25)' }
      case 'POKEMON': return { color: 'var(--game-pokemon, #FCD34D)', bg: 'rgba(252, 211, 77, 0.10)', border: 'rgba(252, 211, 77, 0.25)' }
      case 'YUGIOH': return { color: 'var(--game-ygo, #60A5FA)', bg: 'rgba(96, 165, 250, 0.10)', border: 'rgba(96, 165, 250, 0.25)' }
      case 'ONEPIECE':
      case 'OPTCG':
        return { color: 'var(--game-op, #34D399)', bg: 'rgba(52, 211, 153, 0.10)', border: 'rgba(52, 211, 153, 0.25)' }
      default: return { color: 'var(--text-secondary, #B8B0D8)', bg: 'var(--bg-surface-2, #21203A)', border: 'var(--border-default, #2C2A4A)' }
    }
  }
  
  return (
    <div className="flex items-center gap-3">
      {/* Deck name */}
      {isEditing ? (
        <div className="flex items-center gap-2">
          <Input
            value={editedName}
            onChange={(e) => setEditedName(e.target.value)}
            className="h-8 w-48"
            autoFocus
            onKeyDown={(e) => {
              if (e.key === 'Enter') handleSaveName()
              if (e.key === 'Escape') handleCancelEdit()
            }}
          />
          <Button
            size="small"
            variant="text"
            className="h-8 w-8 p-0"
            onClick={handleSaveName}
          >
            <Check className="h-4 w-4" />
          </Button>
          <Button
            size="small"
            variant="text"
            className="h-8 w-8 p-0"
            onClick={handleCancelEdit}
          >
            <X className="h-4 w-4" />
          </Button>
        </div>
      ) : (
        <div className="flex items-center gap-2">
          <h1
            className="font-barlow font-semibold"
            style={{ fontSize: 18, color: "var(--text-primary, #F0EEFF)" }}
          >
            {deck.name}
          </h1>
          <Button
            size="small"
            variant="text"
            className="h-8 w-8 p-0"
            onClick={() => setIsEditing(true)}
          >
            <Edit2 className="h-3 w-3" />
          </Button>
        </div>
      )}

      {/* Game badge */}
      {(() => {
        const gs = getGameStyle(deck.game)
        return (
          <span
            className="text-xs font-semibold px-3 py-1 rounded-full"
            style={{ color: gs.color, background: gs.bg, border: `1px solid ${gs.border}` }}
          >
            {deck.game}
          </span>
        )
      })()}

      {/* Format badge */}
      <span
        className="text-xs font-medium px-3 py-1 rounded-full"
        style={{ color: "var(--text-secondary, #B8B0D8)", background: "var(--bg-surface-3, #2C2A4A)", border: "1px solid var(--border-default, #2C2A4A)" }}
      >
        {deck.format}
      </span>

      {/* Card count */}
      <span
        className="text-xs font-mono font-medium px-3 py-1 rounded-full"
        style={{ color: "var(--brand-primary, #8B5CF6)", background: "rgba(139, 92, 246, 0.1)", border: "1px solid rgba(139, 92, 246, 0.25)" }}
      >
        {stats.mainDeckSize} cards
      </span>
      
      {/* Enhanced Validation status */}
      {realtimeValidation && (
        <ValidationStatusBadge validation={realtimeValidation.validation} />
      )}
      
      {/* Public/Private toggle */}
      <Button
        size="small"
        variant="text"
        className="h-8 w-8 p-0"
        onClick={togglePublicVisibility}
        title={deck.isPublic ? 'Deck is public' : 'Deck is private'}
      >
        {deck.isPublic ? (
          <Globe className="h-4 w-4" />
        ) : (
          <Lock className="h-4 w-4" />
        )}
      </Button>
    </div>
  )
}

'use client'

import React from 'react'
import { useDrop } from 'react-dnd'
import { cn } from '@/lib/utils'
import { Deck, DeckCard } from '@/types/deck'
import { useDeckBuilder } from '@/contexts/DeckBuilderContext'
import { DeckZone } from './DeckZone'
import { DeckStats } from './DeckStats'
import { DeckValidationPanel, ValidationStatusBadge } from './DeckValidationPanel'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Card } from '@/components/atoms/Card/Card'

interface DeckSurfaceProps {
  deck: Deck
  className?: string
}

export function DeckSurface({ deck, className }: DeckSurfaceProps) {
  const { stats, validation, format, realtimeValidation, validateDeck } = useDeckBuilder()
  
  // Determine which zones to show based on game
  const getZonesForGame = () => {
    switch (deck.game) {
      case 'MTG':
        return ['main', 'sideboard', 'commander']
      case 'POKEMON':
        return ['main', 'bench']
      case 'YUGIOH':
        return ['main', 'extra', 'side']
      case 'ONEPIECE':
        return ['main', 'don']
      default:
        return ['main', 'sideboard']
    }
  }
  
  const zones = getZonesForGame()
  
  return (
    <div className={cn('space-y-4', className)}>
      {/* Deck Statistics Card */}
      <Card className="p-4">
        <DeckStats deck={deck} />
      </Card>
      
      {/* Deck Zones */}
      <Tabs defaultValue="zones" className="w-full">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="zones">Deck Zones</TabsTrigger>
          <TabsTrigger value="list">Card List</TabsTrigger>
        </TabsList>
        
        <TabsContent value="zones" className="space-y-4">
          {/* Main Deck Zone */}
          {zones.includes('main') && (
            <DeckZone
              title="Main Deck"
              zone="main"
              cards={deck.cards.main || []}
              maxCards={format?.minDeckSize}
              validation={validation.errors.filter(e => e.zone === 'main')}
              className="min-h-[300px]"
            />
          )}
          
          {/* Sideboard Zone */}
          {zones.includes('sideboard') && (
            <DeckZone
              title="Sideboard"
              zone="sideboard"
              cards={deck.cards.sideboard || []}
              maxCards={format?.sideboardSize || 15}
              validation={validation.errors.filter(e => e.zone === 'sideboard')}
              className="min-h-[150px]"
            />
          )}
          
          {/* Commander Zone (MTG) */}
          {zones.includes('commander') && deck.game === 'MTG' && (
            <DeckZone
              title="Commander"
              zone="commander"
              cards={deck.cards.commander || []}
              maxCards={deck.format === 'Commander' ? 1 : 0}
              validation={validation.errors.filter(e => e.zone === 'commander')}
              className="min-h-[100px]"
            />
          )}
          
          {/* Extra Deck Zone (Yu-Gi-Oh!) */}
          {zones.includes('extra') && deck.game === 'YUGIOH' && (
            <DeckZone
              title="Extra Deck"
              zone="extra"
              cards={deck.cards.extra || []}
              maxCards={15}
              validation={validation.errors.filter(e => e.zone === 'extra')}
              className="min-h-[150px]"
            />
          )}
        </TabsContent>
        
        <TabsContent value="list" className="space-y-2">
          <DeckListView deck={deck} />
        </TabsContent>
      </Tabs>
      
      {/* Enhanced Validation Panel */}
      {realtimeValidation && (
        <DeckValidationPanel
          validation={realtimeValidation.validation}
          onRevalidate={validateDeck}
          onFixCard={(cardSku, zone) => {
            // Navigate to card or highlight it
            console.log('Fix card:', cardSku, 'in zone:', zone)
          }}
        />
      )}
    </div>
  )
}

function DeckListView({ deck }: { deck: Deck }) {
  const { updateCardQuantity, removeCard } = useDeckBuilder()
  
  const groupCardsByType = (cards: DeckCard[]) => {
    const grouped: { [key: string]: DeckCard[] } = {}
    
    cards.forEach(card => {
      const type = card.card.type_line?.split(' — ')[0] || 'Unknown'
      if (!grouped[type]) {
        grouped[type] = []
      }
      grouped[type].push(card)
    })
    
    return grouped
  }
  
  const mainDeckByType = groupCardsByType(deck.cards.main || [])
  const sideboardCards = deck.cards.sideboard || []
  
  return (
    <div className="space-y-4">
      {/* Main Deck List */}
      <div>
        <h3 className="font-semibold mb-2">Main Deck ({deck.cards.main?.length || 0})</h3>
        <div className="space-y-2">
          {Object.entries(mainDeckByType).map(([type, cards]) => (
            <div key={type}>
              <h4 className="text-sm font-medium text-muted-foreground mb-1">
                {type} ({cards.reduce((sum, c) => sum + c.quantity, 0)})
              </h4>
              <div className="space-y-1">
                {cards.map((card) => (
                  <DeckListItem
                    key={card.catalogSku}
                    card={card}
                    onQuantityChange={(qty) => updateCardQuantity(card.catalogSku, 'main', qty)}
                    onRemove={() => removeCard(card.catalogSku, 'main', card.quantity)}
                  />
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
      
      {/* Sideboard List */}
      {sideboardCards.length > 0 && (
        <div>
          <h3 className="font-semibold mb-2">
            Sideboard ({sideboardCards.reduce((sum, c) => sum + c.quantity, 0)})
          </h3>
          <div className="space-y-1">
            {sideboardCards.map((card) => (
              <DeckListItem
                key={card.catalogSku}
                card={card}
                onQuantityChange={(qty) => updateCardQuantity(card.catalogSku, 'sideboard', qty)}
                onRemove={() => removeCard(card.catalogSku, 'sideboard', card.quantity)}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

function DeckListItem({ 
  card, 
  onQuantityChange, 
  onRemove 
}: { 
  card: DeckCard
  onQuantityChange: (qty: number) => void
  onRemove: () => void
}) {
  return (
    <div className="flex items-center justify-between py-1 px-2 hover:bg-muted/50 rounded">
      <div className="flex items-center gap-2">
        <input
          type="number"
          value={card.quantity}
          onChange={(e) => onQuantityChange(parseInt(e.target.value) || 0)}
          className="w-12 px-1 py-0 text-center border rounded"
          min="0"
          max="99"
        />
        <span className="text-sm">{card.card.name}</span>
        {card.isFoil && (
          <span className="text-xs text-muted-foreground">(Foil)</span>
        )}
      </div>
      <button
        onClick={onRemove}
        className="text-xs transition-opacity hover:opacity-80"
        style={{ color: "var(--negative, #EF4444)" }}
      >
        Remove
      </button>
    </div>
  )
}

'use client'

import React, { useState } from 'react'
import { useDrop, useDrag } from 'react-dnd'
import { cn } from '@/lib/utils'
import { DeckCard } from '@/types/deck'
import { useDeckBuilder } from '@/contexts/DeckBuilderContext'
import { Card } from '@/components/atoms/Card/Card'
import { ScrollArea } from '@/components/ui/scroll-area'
import Image from 'next/image'
import { Plus, Minus, X } from 'lucide-react'
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"

interface DeckZoneProps {
  title: string
  zone: 'main' | 'sideboard' | 'commander' | 'extra'
  cards: DeckCard[]
  maxCards?: number
  validation?: any[]
  className?: string
}

export function DeckZone({ 
  title, 
  zone, 
  cards, 
  maxCards, 
  validation = [],
  className 
}: DeckZoneProps) {
  const { addCard, removeCard, updateCardQuantity } = useDeckBuilder()
  const [showClearDialog, setShowClearDialog] = useState(false)

  const handleClearConfirmed = () => {
    cards.forEach(card => removeCard(card.catalogSku, zone, card.quantity))
    setShowClearDialog(false)
  }
  
  const totalCards = cards.reduce((sum, card) => sum + card.quantity, 0)
  const hasErrors = validation.length > 0
  
  // Setup drag and drop
  const [{ isOver, canDrop }, drop] = useDrop({
    accept: 'CARD',
    drop: (item: { card: any; deck?: any }) => {
      // Handle both old and new card structures
      const cardToAdd = item.card
      addCard(cardToAdd, zone)
    },
    collect: (monitor) => ({
      isOver: monitor.isOver(),
      canDrop: monitor.canDrop(),
    }),
  })
  
  const isActive = isOver && canDrop
  
  return (
    <div
      ref={drop as any}
      className={cn(
        'transition-all',
        {
          'ring-2 ring-primary': isActive,
          'bg-primary/5': isOver,
        },
        className
      )}
    >
      <Card
        className="p-4"
        style={hasErrors ? { borderColor: "var(--negative, #EF4444)" } : undefined}
      >
      {/* Zone Header */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <h3 className="font-semibold">{title}</h3>
          <span
            className="px-2 py-0.5 text-xs font-medium rounded-full"
            style={hasErrors
              ? { background: "rgba(239, 68, 68, 0.15)", color: "var(--negative, #EF4444)" }
              : { background: "rgba(139, 92, 246, 0.15)", color: "var(--brand-primary, #8B5CF6)" }
            }
          >
            {totalCards}{maxCards ? ` / ${maxCards}` : ''}
          </span>
        </div>
        
        {/* Zone Actions */}
        <div className="flex items-center gap-1">
          {cards.length > 0 && (
            <button
              onClick={() => setShowClearDialog(true)}
              className="text-xs text-muted-foreground hover:text-destructive"
            >
              Clear
            </button>
          )}
        </div>
      </div>
      
      {/* Drop Zone Indicator */}
      {cards.length === 0 && !isOver && (
        <div className="flex items-center justify-center h-24 border-2 border-dashed border-muted-foreground/30 rounded-lg">
          <p className="text-sm text-muted-foreground">
            Drag cards here to add to {title.toLowerCase()}
          </p>
        </div>
      )}
      
      {/* Cards Grid */}
      {cards.length > 0 && (
        <ScrollArea className="h-full">
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-2">
            {cards.map((card) => (
              <DeckCardItem
                key={card.catalogSku}
                card={card}
                zone={zone}
                onQuantityChange={(qty) => updateCardQuantity(card.catalogSku, zone, qty)}
                onRemove={() => removeCard(card.catalogSku, zone, card.quantity)}
              />
            ))}
          </div>
        </ScrollArea>
      )}
      
      {/* Drop Overlay */}
      {isOver && (
        <div className="absolute inset-0 bg-primary/10 rounded-lg pointer-events-none flex items-center justify-center">
          <div className="bg-background/90 px-4 py-2 rounded-md">
            <p className="text-sm font-medium">Drop to add to {title}</p>
          </div>
        </div>
      )}
      </Card>

      <AlertDialog open={showClearDialog} onOpenChange={setShowClearDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Clear {title}?</AlertDialogTitle>
            <AlertDialogDescription>
              All cards will be removed from {title}. You can always add them back.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleClearConfirmed}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Clear cards
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

interface DeckCardItemProps {
  card: DeckCard
  zone: string
  onQuantityChange: (qty: number) => void
  onRemove: () => void
}

function DeckCardItem({ card, zone, onQuantityChange, onRemove }: DeckCardItemProps) {
  const { moveCard } = useDeckBuilder()
  
  // Setup drag for moving cards between zones
  const [{ isDragging }, drag] = useDrag({
    type: 'DECK_CARD',
    item: { card, fromZone: zone },
    collect: (monitor) => ({
      isDragging: monitor.isDragging(),
    }),
  })
  
  const imageUrl = card.card.image_uris?.small || card.card.image_uris?.normal || '/placeholder-card.png'
  
  return (
    <div
      ref={drag as any}
      className={cn(
        'relative group cursor-move transition-all',
        isDragging && 'opacity-50'
      )}
    >
      {/* Card Image */}
      <div className="relative aspect-[2.5/3.5] rounded-md overflow-hidden bg-muted">
        <Image
          src={imageUrl}
          alt={card.card.name}
          fill
          className="object-cover"
          sizes="(max-width: 640px) 50vw, (max-width: 768px) 33vw, 20vw"
        />
        
        {/* Quantity Badge */}
        {card.quantity > 1 && (
          <span
            className="absolute top-1 right-1 h-5 w-5 flex items-center justify-center text-xs font-medium rounded-full text-white"
            style={{ background: "var(--brand-primary, #8B5CF6)" }}
          >
            {card.quantity}
          </span>
        )}
        
        {/* Foil Indicator */}
        {card.isFoil && (
          <div className="absolute top-1 left-1 w-4 h-4 rounded-full" style={{ background: "linear-gradient(135deg, #FBBF24, #D97706)" }} />
        )}
        
        {/* Hover Controls */}
        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-1">
          <button
            onClick={(e) => {
              e.stopPropagation()
              onQuantityChange(card.quantity - 1)
            }}
            className="p-1 bg-background/90 rounded hover:bg-background"
            disabled={card.quantity <= 1}
          >
            <Minus className="h-3 w-3" />
          </button>
          
          <span className="px-2 py-1 bg-background/90 rounded text-xs font-medium">
            {card.quantity}
          </span>
          
          <button
            onClick={(e) => {
              e.stopPropagation()
              onQuantityChange(card.quantity + 1)
            }}
            className="p-1 bg-background/90 rounded hover:bg-background"
          >
            <Plus className="h-3 w-3" />
          </button>
          
          <button
            onClick={(e) => {
              e.stopPropagation()
              onRemove()
            }}
            className="p-1 rounded text-white ml-1 transition-opacity hover:opacity-90"
            style={{ background: "var(--negative, #EF4444)" }}
          >
            <X className="h-3 w-3" />
          </button>
        </div>
      </div>
      
      {/* Card Name */}
      <p className="text-xs mt-1 truncate" title={card.card.name}>
        {card.card.name}
      </p>
    </div>
  )
}

"use client"

import { useState } from "react"
import { cn } from "@/lib/utils"
import { useDeckBuilder } from "@/contexts/DeckBuilderContext"
import { CardBrowseInterface } from "@/components/cards/CardBrowseInterface"
import { CreateDeckModal } from "./CreateDeckModal"
import { DeckCoverManager } from "./DeckCoverManager"
import { DeckSocialFeatures } from "./DeckSocialFeatures"
import { DeckPrivacyControls } from "./DeckPrivacyControls"
import { Button } from "@/components/atoms/Button/Button"
import { OptimizedImage } from "@/components/ui/OptimizedImage"
import {
  Plus,
  Search,
  FileText,
  Settings,
  Save,
  MoreHorizontal,
  ChevronDown,
  ChevronUp,
  Grid3x3,
  Eye,
  EyeOff,
  Heart,
  Share,
  Copy,
  Edit,
  Trash2,
  ArrowLeft
} from "lucide-react"
import { DndProvider } from "react-dnd"
import { HTML5Backend } from "react-dnd-html5-backend"
import { TouchBackend } from "react-dnd-touch-backend"
import { Deck } from "@/types/deck"

interface MobileDeckBuilderProps {
  className?: string
}

type MobileView = 'overview' | 'deck' | 'browse' | 'settings'

export function MobileDeckBuilder({ className }: MobileDeckBuilderProps) {
  const {
    deck,
    isDirty,
    isSaving,
    saveDeck,
    addCard,
    createDeck,
    updateCardQuantity,
    removeCard
  } = useDeckBuilder()
  
  const [activeView, setActiveView] = useState<MobileView>('overview')
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [expandedZones, setExpandedZones] = useState<Record<string, boolean>>({
    main: true,
    sideboard: false,
    commander: false,
    extra: false
  })
  
  // Detect if device supports touch
  const isTouchDevice = typeof window !== 'undefined' && 'ontouchstart' in window
  const dndBackend = isTouchDevice ? TouchBackend : HTML5Backend
  
  // Show welcome screen when no deck is loaded
  if (!deck) {
    return (
      <div className={cn("flex flex-col min-h-screen bg-background", className)}>
        {/* Mobile Header */}
        <div className="sticky top-0 z-10 bg-background border-b px-4 py-3">
          <h1 className="text-lg font-semibold">Deck Builder</h1>
        </div>
        
        {/* Welcome Content */}
        <div className="flex-1 flex items-center justify-center p-6">
          <div className="text-center max-w-sm space-y-6">
            <div className="w-20 h-20 mx-auto bg-primary/10 rounded-full flex items-center justify-center">
              <FileText className="w-8 h-8 text-primary" />
            </div>
            
            <div>
              <h2 className="text-xl font-bold mb-2">Build Your Deck</h2>
              <p className="text-muted-foreground text-sm">
                Create competitive decks for MTG, Pokémon, Yu-Gi-Oh!, and One Piece
              </p>
            </div>
            
            <Button
              onClick={() => setShowCreateModal(true)}
              size="large"
              className="w-full"
            >
              <Plus className="w-4 h-4 mr-2" />
              Create New Deck
            </Button>
            
            <div className="space-y-2 text-xs text-muted-foreground">
              <div className="flex items-center gap-2">
                <div className="w-1 h-1 bg-primary rounded-full" />
                <span>Format validation for all games</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-1 h-1 bg-primary rounded-full" />
                <span>Real-time pricing integration</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-1 h-1 bg-primary rounded-full" />
                <span>Community sharing features</span>
              </div>
            </div>
          </div>
        </div>
        
        <CreateDeckModal
          isOpen={showCreateModal}
          onClose={() => setShowCreateModal(false)}
          onCreated={(newDeck) => {
            createDeck(newDeck.name, newDeck.game, newDeck.format)
            setShowCreateModal(false)
          }}
        />
      </div>
    )
  }
  
  return (
    <DndProvider backend={dndBackend}>
      <div className={cn("flex flex-col min-h-screen bg-background", className)}>
        {/* Mobile Header */}
        <MobileDeckHeader
          deck={deck}
          isDirty={isDirty}
          isSaving={isSaving}
          onSave={saveDeck}
        />
        
        {/* View Content */}
        <div className="flex-1">
          {activeView === 'overview' && (
            <MobileDeckOverview 
              deck={deck}
              expandedZones={expandedZones}
              onZoneToggle={(zone) => setExpandedZones(prev => ({ ...prev, [zone]: !prev[zone] }))}
              onCardQuantityChange={updateCardQuantity}
              onCardRemove={removeCard}
            />
          )}
          
          {activeView === 'deck' && (
            <MobileDeckZones
              deck={deck}
              onCardAdd={addCard}
              onCardQuantityChange={updateCardQuantity}
              onCardRemove={removeCard}
            />
          )}
          
          {activeView === 'browse' && (
            <div className="lg:hidden h-full">
              <CardBrowseInterface
                isDeckBuilder={true}
                lockedGame={deck.game}
                lockedGameDisplayName={deck.game}
                lockedFormat={deck.format}
                title="Add Cards to Deck"
                description={`Browse ${deck.game} cards${deck.format ? ` for ${deck.format}` : ''}`}
                showGameBadges={false}
                hideGameFilter={true}
                onCardAdd={(card, zone) => addCard(card, zone || 'main')}
                enableDragDrop={true}
                className="h-full"
              />
            </div>
          )}
          
          {activeView === 'settings' && (
            <MobileDeckSettings deck={deck} />
          )}
        </div>
        
        {/* Bottom Navigation */}
        <MobileBottomNavigation
          activeView={activeView}
          onViewChange={setActiveView}
          deck={deck}
        />
      </div>
    </DndProvider>
  )
}

// Mobile Header Component
function MobileDeckHeader({
  deck,
  isDirty,
  isSaving,
  onSave
}: {
  deck: Deck
  isDirty: boolean
  isSaving: boolean
  onSave: () => void
}) {
  return (
    <div className="sticky top-0 z-10 bg-background/95 backdrop-blur border-b">
      <div className="flex items-center justify-between px-4 py-3">
        <div className="flex items-center gap-3 min-w-0">
          <div className="min-w-0">
            <h1 className="font-semibold truncate">{deck.name}</h1>
            <div className="flex items-center gap-2 text-xs">
              <span
                className="px-2 py-0.5 text-xs font-medium rounded-full"
                style={{ background: "rgba(139, 92, 246, 0.15)", color: "var(--brand-primary, #8B5CF6)" }}
              >
                {deck.game}
              </span>
              {deck.format && (
                <span
                  className="px-2 py-0.5 text-xs font-medium rounded-full"
                  style={{ background: "var(--bg-surface-3, #2C2A4A)", color: "var(--text-secondary, #B8B0D8)", border: "1px solid var(--border-default, #2C2A4A)" }}
                >
                  {deck.format}
                </span>
              )}
            </div>
          </div>
        </div>
        
        <div className="flex items-center gap-1">
          <Button
            variant={isDirty ? "filled" : "text"}
            size="small"
            onClick={onSave}
            disabled={!isDirty || isSaving}
            className="h-8 px-2 text-xs"
          >
            <Save className="h-3 w-3 mr-1" />
            {isSaving ? 'Saving...' : isDirty ? 'Save' : 'Saved'}
          </Button>
        </div>
      </div>
    </div>
  )
}

// Mobile Bottom Navigation
function MobileBottomNavigation({
  activeView,
  onViewChange,
  deck
}: {
  activeView: MobileView
  onViewChange: (view: MobileView) => void
  deck: Deck
}) {
  const totalCards = (deck.cards.main?.length || 0) + 
                    (deck.cards.sideboard?.length || 0) +
                    (deck.cards.commander?.length || 0) + 
                    (deck.cards.extra?.length || 0)
  
  const navItems = [
    {
      id: 'overview' as MobileView,
      label: 'Overview',
      icon: Grid3x3,
      badge: null
    },
    {
      id: 'deck' as MobileView,
      label: 'Deck',
      icon: FileText,
      badge: totalCards > 0 ? totalCards : null
    },
    {
      id: 'browse' as MobileView,
      label: 'Browse',
      icon: Search,
      badge: null
    },
    {
      id: 'settings' as MobileView,
      label: 'Settings',
      icon: Settings,
      badge: null
    }
  ]
  
  return (
    <div className="sticky bottom-0 bg-background border-t">
      <div className="flex">
        {navItems.map((item) => {
          const Icon = item.icon
          const isActive = activeView === item.id
          
          return (
            <button
              key={item.id}
              onClick={() => onViewChange(item.id)}
              className={cn(
                "flex-1 flex flex-col items-center gap-1 py-3 relative transition-colors",
                isActive 
                  ? "text-primary" 
                  : "text-muted-foreground hover:text-foreground"
              )}
            >
              <Icon className="h-5 w-5" />
              <span className="text-xs font-medium">{item.label}</span>
              {item.badge && (
                <div className="absolute -top-1 right-1/2 translate-x-2 bg-primary text-primary-foreground text-xs rounded-full h-5 w-5 flex items-center justify-center">
                  {item.badge}
                </div>
              )}
            </button>
          )
        })}
      </div>
    </div>
  )
}

// Mobile Deck Overview
function MobileDeckOverview({
  deck,
  expandedZones,
  onZoneToggle,
  onCardQuantityChange,
  onCardRemove
}: {
  deck: Deck
  expandedZones: Record<string, boolean>
  onZoneToggle: (zone: string) => void
  onCardQuantityChange: (catalogSku: string, zone: string, quantity: number) => void
  onCardRemove: (catalogSku: string, zone: string, quantity: number) => void
}) {
  const zones = [
    { id: 'main', title: 'Main Deck', cards: deck.cards.main || [] },
    { id: 'sideboard', title: 'Sideboard', cards: deck.cards.sideboard || [] },
    { id: 'commander', title: 'Commander', cards: deck.cards.commander || [] },
    { id: 'extra', title: 'Extra Deck', cards: deck.cards.extra || [] }
  ].filter(zone => zone.cards.length > 0)
  
  return (
    <div className="p-4 space-y-4">
      {/* Deck Cover */}
      <div className="bg-card rounded-lg p-4 border border-border">
        <DeckCoverManager
          deck={deck as any}
          onCoverChange={async (cardId) => {
            // Handle cover change
          }}
          variant="preview"
          className="w-full max-w-32 mx-auto mb-4"
        />
        
        {deck.description && (
          <p className="text-sm text-muted-foreground text-center">
            {deck.description}
          </p>
        )}
      </div>
      
      {/* Quick Stats */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-card rounded-lg p-4 border border-border text-center">
          <div className="text-2xl font-bold">
            {deck.cards.main?.reduce((sum, card) => sum + (card.quantity || 1), 0) || 0}
          </div>
          <div className="text-sm text-muted-foreground">Main Deck</div>
        </div>
        
        <div className="bg-card rounded-lg p-4 border border-border text-center">
          <div className="text-2xl font-bold">
            {zones.length}
          </div>
          <div className="text-sm text-muted-foreground">Zones</div>
        </div>
      </div>
      
      {/* Zone Lists */}
      <div className="space-y-3">
        {zones.map((zone) => (
          <div key={zone.id} className="bg-card rounded-lg border border-border">
            <button
              onClick={() => onZoneToggle(zone.id)}
              className="w-full flex items-center justify-between p-4 text-left"
            >
              <div>
                <h3 className="font-medium">{zone.title}</h3>
                <p className="text-sm text-muted-foreground">
                  {zone.cards.reduce((sum, card) => sum + (card.quantity || 1), 0)} cards
                </p>
              </div>
              {expandedZones[zone.id] ? (
                <ChevronUp className="h-4 w-4" />
              ) : (
                <ChevronDown className="h-4 w-4" />
              )}
            </button>
            
            {expandedZones[zone.id] && (
              <div className="border-t border-border p-4 space-y-2">
                {zone.cards.map((card) => (
                  <MobileCardItem
                    key={card.catalogSku}
                    card={card}
                    zone={zone.id}
                    onQuantityChange={onCardQuantityChange}
                    onRemove={onCardRemove}
                  />
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  )
}

// Mobile Card Item
function MobileCardItem({
  card,
  zone,
  onQuantityChange,
  onRemove
}: {
  card: any
  zone: string
  onQuantityChange: (catalogSku: string, zone: string, quantity: number) => void
  onRemove: (catalogSku: string, zone: string, quantity: number) => void
}) {
  return (
    <div className="flex items-center gap-3 p-2 bg-muted/50 rounded-lg">
      <div className="w-10 h-14 bg-muted rounded overflow-hidden flex-shrink-0">
        {card.card?.imageUrl ? (
          <OptimizedImage
            src={card.card.imageUrl}
            alt={card.card.name}
            width={40}
            height={56}
            className="w-full h-full object-contain"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <Grid3x3 className="h-4 w-4 text-muted-foreground" />
          </div>
        )}
      </div>
      
      <div className="flex-1 min-w-0">
        <h4 className="font-medium text-sm truncate">{card.card?.name}</h4>
        <div className="flex items-center gap-2 text-xs text-muted-foreground">
          {card.card?.type && <span>{card.card.type}</span>}
          {card.card?.rarity && (
            <>
              <span>•</span>
              <span className="capitalize">{card.card.rarity}</span>
            </>
          )}
        </div>
      </div>
      
      <div className="flex items-center gap-2">
        <div className="flex items-center bg-background rounded border">
          <button
            onClick={() => onQuantityChange(card.catalogSku, zone, Math.max(0, (card.quantity || 1) - 1))}
            className="p-1 hover:bg-muted"
          >
            <Minus className="h-3 w-3" />
          </button>
          <span className="px-2 py-1 text-sm font-medium min-w-8 text-center">
            {card.quantity || 1}
          </span>
          <button
            onClick={() => onQuantityChange(card.catalogSku, zone, (card.quantity || 1) + 1)}
            className="p-1 hover:bg-muted"
          >
            <Plus className="h-3 w-3" />
          </button>
        </div>
        
        <button
          onClick={() => onRemove(card.catalogSku, zone, card.quantity || 1)}
          className="p-1 transition-opacity hover:opacity-80"
          style={{ color: "var(--negative, #EF4444)" }}
        >
          <Trash2 className="h-3 w-3" />
        </button>
      </div>
    </div>
  )
}

// Mobile Deck Zones (Visual deck view)
function MobileDeckZones({
  deck,
  onCardAdd,
  onCardQuantityChange,
  onCardRemove
}: {
  deck: Deck
  onCardAdd: (card: any, zone: 'main' | 'sideboard' | 'commander' | 'extra', quantity?: number) => void
  onCardQuantityChange: (catalogSku: string, zone: string, quantity: number) => void
  onCardRemove: (catalogSku: string, zone: string, quantity: number) => void
}) {
  return (
    <div className="h-full overflow-y-auto p-4 space-y-4">
      {/* Main Deck */}
      <MobileDeckZone
        title="Main Deck"
        zone="main"
        cards={deck.cards.main || []}
        onCardAdd={onCardAdd}
        onCardQuantityChange={onCardQuantityChange}
        onCardRemove={onCardRemove}
      />
      
      {/* Sideboard */}
      {(deck.cards.sideboard?.length || 0) > 0 && (
        <MobileDeckZone
          title="Sideboard"
          zone="sideboard"
          cards={deck.cards.sideboard || []}
          onCardAdd={onCardAdd}
          onCardQuantityChange={onCardQuantityChange}
          onCardRemove={onCardRemove}
        />
      )}
      
      {/* Commander */}
      {(deck.cards.commander?.length || 0) > 0 && (
        <MobileDeckZone
          title="Commander"
          zone="commander"
          cards={deck.cards.commander || []}
          onCardAdd={onCardAdd}
          onCardQuantityChange={onCardQuantityChange}
          onCardRemove={onCardRemove}
        />
      )}
      
      {/* Extra Deck */}
      {(deck.cards.extra?.length || 0) > 0 && (
        <MobileDeckZone
          title="Extra Deck"
          zone="extra"
          cards={deck.cards.extra || []}
          onCardAdd={onCardAdd}
          onCardQuantityChange={onCardQuantityChange}
          onCardRemove={onCardRemove}
        />
      )}
    </div>
  )
}

// Mobile Deck Zone
function MobileDeckZone({
  title,
  zone,
  cards,
  onCardAdd,
  onCardQuantityChange,
  onCardRemove
}: {
  title: string
  zone: 'main' | 'sideboard' | 'commander' | 'extra'
  cards: any[]
  onCardAdd: (card: any, zone: 'main' | 'sideboard' | 'commander' | 'extra', quantity?: number) => void
  onCardQuantityChange: (catalogSku: string, zone: string, quantity: number) => void
  onCardRemove: (catalogSku: string, zone: string, quantity: number) => void
}) {
  const totalCards = cards.reduce((sum, card) => sum + (card.quantity || 1), 0)
  
  return (
    <div className="bg-card border border-border rounded-lg p-4">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-semibold">{title}</h3>
        <span
          className="px-2 py-0.5 text-xs font-medium rounded-full"
          style={{ background: "var(--bg-surface-3, #2C2A4A)", color: "var(--text-secondary, #B8B0D8)" }}
        >{totalCards}</span>
      </div>
      
      {cards.length === 0 ? (
        <div className="h-24 border-2 border-dashed border-muted-foreground/30 rounded-lg flex items-center justify-center">
          <p className="text-sm text-muted-foreground text-center">
            No cards in {title.toLowerCase()}
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-4 gap-2">
          {cards.map((card) => (
            <div key={card.catalogSku} className="relative aspect-[3/4]">
              <div className="w-full h-full bg-muted rounded overflow-hidden">
                {card.card?.imageUrl ? (
                  <OptimizedImage
                    src={card.card.imageUrl}
                    alt={card.card.name}
                    width={100}
                    height={140}
                    sizes="25vw"
                    className="object-contain"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <Grid3x3 className="h-4 w-4 text-muted-foreground" />
                  </div>
                )}
              </div>
              
              {(card.quantity || 1) > 1 && (
                <div className="absolute top-1 right-1 bg-primary text-primary-foreground text-xs rounded-full h-5 w-5 flex items-center justify-center">
                  {card.quantity}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  )
}

// Mobile Deck Settings
function MobileDeckSettings({ deck }: { deck: Deck }) {
  return (
    <div className="p-4 space-y-6">
      {/* Privacy Controls */}
      <div>
        <h3 className="font-semibold mb-3">Privacy</h3>
        <DeckPrivacyControls
          deck={deck as any}
          onPrivacyUpdate={async (updates) => {
            // Handle privacy update
          }}
          compact
        />
      </div>
      
      {/* Social Features */}
      {deck.stats && (
        <div>
          <h3 className="font-semibold mb-3">Community</h3>
          <DeckSocialFeatures
            deckId={deck.id}
            stats={deck.stats as any}
            variant="compact"
            onLike={async () => {}}
            onCopy={async () => {}}
            onShare={() => {}}
          />
        </div>
      )}
      
      {/* Cover Image */}
      <div>
        <h3 className="font-semibold mb-3">Cover Image</h3>
        <DeckCoverManager
          deck={deck as any}
          onCoverChange={async () => {}}
          variant="inline"
        />
      </div>
      
      {/* Export/Import */}
      <div>
        <h3 className="font-semibold mb-3">Export & Import</h3>
        <div className="space-y-2">
          <Button variant="tonal" className="w-full justify-start">
            <FileText className="h-4 w-4 mr-2" />
            Export to Text
          </Button>
          <Button variant="tonal" className="w-full justify-start">
            <Share className="h-4 w-4 mr-2" />
            Share Deck Link
          </Button>
        </div>
      </div>
    </div>
  )
}

