// Mobile Header Component — glassmorphic, matching desktop toolbar language
function MobileDeckHeader({
  deck,
  isDirty,
  isSaving,
  onSave
}: {
  deck: Deck
  isDirty: boolean
  isSaving: boolean
  onSave: () => void
}) {
  const getGameColor = (game: string) => {
    switch (game) {
      case 'MTG': return 'var(--game-mtg, #A78BFA)'
      case 'POKEMON': return 'var(--game-pokemon, #FCD34D)'
      case 'YUGIOH': return 'var(--game-ygo, #60A5FA)'
      case 'ONEPIECE':
      case 'OPTCG': return 'var(--game-op, #34D399)'
      default: return 'var(--brand-primary, #8B5CF6)'
    }
  }
  const gameColor = getGameColor(deck.game)

  return (
    <div
      style={{
        position: "sticky",
        top: 0,
        zIndex: 10,
        background: "rgba(24, 22, 42, 0.88)",
        backdropFilter: "blur(16px)",
        WebkitBackdropFilter: "blur(16px)",
        borderBottom: "1px solid var(--border-default, #2C2A4A)",
      }}
    >
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "10px 16px" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10, minWidth: 0 }}>
          <div style={{ minWidth: 0 }}>
            <h1
              style={{
                fontSize: 16,
                fontWeight: 700,
                color: "var(--text-primary, #F0EEFF)",
                margin: 0,
                overflow: "hidden",
                textOverflow: "ellipsis",
                whiteSpace: "nowrap",
                fontFamily: "var(--font-display, 'Barlow Condensed', sans-serif)",
              }}
            >
              {deck.name}
            </h1>
            <div style={{ display: "flex", alignItems: "center", gap: 6, marginTop: 2 }}>
              <span
                style={{
                  fontSize: 10,
                  fontWeight: 700,
                  padding: "1px 8px",
                  borderRadius: 10,
                  color: gameColor,
                  background: `color-mix(in srgb, ${gameColor} 12%, transparent)`,
                  border: `1px solid color-mix(in srgb, ${gameColor} 25%, transparent)`,
                }}
              >
                {deck.game}
              </span>
              {deck.format && (
                <span
                  style={{
                    fontSize: 10,
                    fontWeight: 500,
                    padding: "1px 8px",
                    borderRadius: 10,
                    color: "var(--text-secondary, #B8B0D8)",
                    background: "var(--bg-surface-3, #2C2A4A)",
                    border: "1px solid var(--border-default, #2C2A4A)",
                  }}
                >
                  {deck.format}
                </span>
              )}
            </div>
          </div>
        </div>

        <button
          onClick={onSave}
          disabled={!isDirty || isSaving}
          style={{
            display: "flex",
            alignItems: "center",
            gap: 4,
            height: 32,
            padding: "0 12px",
            borderRadius: 8,
            fontSize: 12,
            fontWeight: 600,
            border: "none",
            cursor: !isDirty || isSaving ? "default" : "pointer",
            ...(isDirty
              ? {
                  color: "#fff",
                  background: "var(--brand-primary, #8B5CF6)",
                  boxShadow: "0 0 8px rgba(139, 92, 246, 0.25)",
                }
              : {
                  color: "var(--text-tertiary, #7B72A8)",
                  background: "transparent",
                  opacity: 0.5,
                }),
          }}
        >
          <Save style={{ width: 13, height: 13 }} />
          {isSaving ? 'Saving…' : isDirty ? 'Save' : 'Saved'}
        </button>
      </div>
    </div>
  )
}

